VALUES
  ('optometrist-moex-01624', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '視力對比敏感度的檢查中，將對比敏感度異常分類型，下列敘述何者正確？', '["第一型對比度缺失（type Ⅰ CS loss）指所有空間頻率都下降，例如：白內障患者", "第二型對比度缺失（type Ⅱ CS loss）指低空間頻率下降，例如：屈光不正未矯正", "第三型對比度缺失（typeⅢCSloss）指低空間頻率下降，通常視力不受影響", "第四型對比度缺失（type Ⅳ CS loss）指高空間頻率都下降，例如：弱視患者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01625', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關影響視力與配鏡的敘述，下列何者正確？①青光眼病患可能造成視野缺損，嚴重者亦會影響視力', '["黃斑部疾病會影響中心視力，使配鏡困難", "圓錐角膜可能造成高度散光，亦會影響視力，造成配鏡困難", "僅", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01626', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列那一因素較不影響聚合近點（nearpointofconvergence）測試之表現？', '["遠及近距離眼位", "近點固視偏差（nearfixationdisparity）", "調節反應", "瞳孔反應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01627', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列色覺檢查中，何者可用以檢查藍-黃（blue-yellow）色覺異常？①石原氏檢查（Ishiharatest）  ②D-15', '["城市大學檢查（CityUniversitytest）", "Hardy-Rand-Rittler（HRR）檢查", "僅", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01628', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關布魯克諾檢查（Brücknertest）的敘述，下列何者正確？', '["慣用檢查距離為40公分", "若患者兩眼未同時注視，則其中眼底反射光較亮者為注視眼", "此法可檢查患者是否有斜視與介質混濁，但較無法檢測雙眼不等視（anisometropia）", "經此法檢查遠視眼，將觀察到較暗新月（darkercrescent）在瞳孔下方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01629', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '視力表依所測視力功能的不同，可分為數種形式。下列何種視力表可用以檢測偵測型視力（detection acuity）？', '["柵欄視力表（gratingchart）", "C字視力表（LandoltCchart）", "圖形視力表（Leasymbols）", "史奈侖視力表（Snellenchart）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01630', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關瞳孔檢查，下列敘述何者錯誤？', '["瞳孔檢查中若發現兩眼瞳孔大小不同，需作暗-亮瞳孔檢查（dim-brightpupillarytest）", "直接瞳孔反應為觀察筆燈照射的眼睛是否出現因光照而產生的縮瞳現象", "手電筒搖擺檢查（swingingflashlighttest）是用來檢查是否有相對性傳入（relativeafferent）異常", "直接和間接瞳孔反應異常時，需要布魯克諾檢查（Brücknertest）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01631', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關像差的敘述，下列何者最不適當？', '["因為眼睛的像差（ocularaberrations），所以瞳孔的各個部分，並非都能測量到相同的屈光度數（refractive power）", "測量高階像差（higher-orderaberrations）的儀器，是指測量瞳孔中心2.0mm直徑範圍以內的屈光狀態", "我們可以用澤氏多項式（Zernikepolynomials）來描述這些像差（aberrations）", "所謂像差是指實際光學系統（opticalsystem）中的前導波（wavefront）偏離了理想的前導波"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01632', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列敘述何者最不適當？', '["自動驗光儀（automatedoptometers）比自覺式驗光（subjectiverefraction）測得比較多的近視或比較少的 遠視", "自動驗光儀比自覺式驗光提供給病人注視的目標物通常比較近", "現代的前導波分析儀（modernwavefrontanalyzers）無法完全去除儀器引起的近視（instrumentmyopia）", "自動驗光儀用可見光測量，不需要輔助的注視目標（auxiliaryfixationtarget）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01633', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '針對有雙眼視覺問題的人，調整度數對下列何種測驗結果最有影響？', '["遮蓋測驗（covertest）", "眼外肌運動（extraocularmotility）", "固視偏差（fixationdisparity）", "AC/A 比值（AC/Aratio）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
